22	const PROCESSING_FEE = 5;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const BLOCK_SIZE = 3;
34	const BLOCK_PRICE = 60;
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	const unitPrice = (type: string): number => BASE_PREMIUMS[type] ?? 0;
38	
39	const countsByType = (items: Item[]): Map<string, number> =>
40	  items.reduce(
41	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
42	    new Map<string, number>()
43	  );
44	
45	const groupTotal = (type: string, count: number): number =>
46	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
47	    ? BLOCK_PRICE
48	    : count * unitPrice(type);
49	
50	const sumBasePremiums = (items: Item[]): number => {
51	  let total = 0;
52	  for (const [type, count] of countsByType(items)) {
53	    total += groupTotal(type, count);
54	  }
55	  return total;
56	};
57	
58	const itemSurcharges = (item: Item): number => {
59	  const base = unitPrice(item.type);
60	  let surcharge = 0;
61	  if (item.cursed) surcharge += base * 0.5;
62	  if ((item.enchantment ?? 0) >= 5) surcharge += base * 0.3;
63	  return surcharge;
64	};
65	
66	const sumItemSurcharges = (items: Item[]): number =>
67	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
68	
69	const quote = (
70	  { items }: QuoteStep,
71	  customer: { yearsWithMHPCO: number }
72	): QuoteResult => {
73	  const basePremiums = sumBasePremiums(items);
74	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? basePremiums * 0.2 : 0;
75	  return {
76	    premium:
77	      basePremiums + sumItemSurcharges(items) - loyaltyDiscount + PROCESSING_FEE,
78	  };
79	};
80	
81	export const runScenario = (scenario: Scenario): ScenarioResult => ({
82	  results: scenario.steps.map((step) => quote(step, scenario.customer)),
83	});
